// src/components/ProjectorSearch.js
import React, { useState } from "react";
import axios from "axios";
import "./ProjectorSearch.css";

const ProjectorSearch = ({ goBack }) => {
  const [room, setRoom] = useState("");
  const [day, setDay] = useState("Monday");
  const [period, setPeriod] = useState(1);
  const [results, setResults] = useState(null);
  const [error, setError] = useState("");

  const handleSearch = async () => {
    if (!room.trim()) {
      setError("Please enter a valid room number.");
      return;
    }
    setError("");

    try {
      const response = await axios.get("/api/projector", {
        params: { room, day, period },
      });      
      setResults(response.data);
    } catch (error) {
      console.error("Error fetching projector data:", error);
      setError("Failed to fetch data. Try again later.");
    }
  };

  const handleReset = () => {
    setRoom("");
    setDay("Monday");
    setPeriod(1);
    setResults(null);
    setError("");
  };

  return (
    <div className="projector-search">
      <h2>Projector Availability Checker</h2>

      <div className="filters">
        <label>Classroom (Room):</label>
        <input
          type="text"
          placeholder="Enter Room"
          value={room}
          onChange={(e) => setRoom(e.target.value)}
        />

        <label>Day:</label>
        <select value={day} onChange={(e) => setDay(e.target.value)}>
          {["Monday", "Tuesday", "Wednesday", "Thursday", "Friday"].map((d) => (
            <option key={d} value={d}>
              {d}
            </option>
          ))}
        </select>

        <label>Period (1-8):</label>
        <select value={period} onChange={(e) => setPeriod(Number(e.target.value))}>
          {[1, 2, 3, 4, 5, 6, 7, 8].map((p) => (
            <option key={p} value={p}>
              {p}
            </option>
          ))}
        </select>
      </div>

      {error && <p className="error">{error}</p>}

      <div className="button-group">
        <button onClick={handleSearch}>Search</button>
        <button onClick={handleReset}>Reset</button>
        <button onClick={goBack}>Back</button>
      </div>

      {results && (
        <div className="results">
          <h3>Results:</h3>
          <pre>{JSON.stringify(results, null, 2)}</pre>
        </div>
      )}
    </div>
  );
};

export default ProjectorSearch;
